const src=$('Score + dedup').first().json;
const toAlert=src.toAlert||[];
const input=$input.first().json,parsed=input?.output,rawText=input?.text;

function fallback(city){
  const w=city.windows?.next6h?.maxScore>=5?'next 6 hours':'next 24-48 hours';
  const h=city.windows?.next6h?.peak||city.windows?.tonight?.peak||{};
  const cnd=h.label||'adverse weather',wnd=h.wind?' with '+Math.round(h.wind)+' kph winds from the '+h.dir:'',pk=city.localCtx?.isPeak?' during the current peak window':'';
  return cnd.charAt(0).toUpperCase()+cnd.slice(1)+wnd+' forecast in the '+w+pk+'. Conditions exceed normal thresholds and are likely to reduce courier supply and extend delivery times. Brief the courier team and consider activating contingency incentives for the affected period.';}

let alerts;
try{
  let data;
  if(Array.isArray(parsed)){data=parsed;}else{
    const raw=(rawText||'').trim().replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
    if(!raw)throw new Error('empty');data=JSON.parse(raw);if(!Array.isArray(data))throw new Error('not array');}
  const VALID=['HEADS_UP','URGENT'];
  alerts=data.map(a=>({city:a.city,severity:VALID.includes(a.severity)?a.severity:'HEADS_UP',message:a.message,aiWritten:true}));
}catch(e){
  alerts=toAlert.map(c=>({city:c.city,severity:c.severity,message:fallback(c),aiWritten:false}));}

return alerts.map(a=>{
  const urgent=a.severity==='URGENT';
  return {json:{city:a.city,blocks:[
    {type:'header',text:{type:'plain_text',text:(urgent?':red_circle: URGENT':':large_yellow_circle: HEADS-UP')+' | '+a.city}},
    {type:'section',text:{type:'mrkdwn',text:a.message+(a.aiWritten?'':' _(auto-generated)_')}},
    {type:'context',elements:[{type:'mrkdwn',text:'Open-Meteo  ·  '+new Date().toUTCString()+'  ·  <https://open-meteo.com|Verify forecast>'}]}
  ]}};});

const WMO={0:'clear sky',1:'mainly clear',2:'partly cloudy',3:'overcast',45:'fog',48:'icy fog',51:'light drizzle',53:'moderate drizzle',55:'dense drizzle',61:'light rain',63:'moderate rain',65:'heavy rain',71:'light snow',73:'moderate snow',75:'heavy snow',77:'snow grains',80:'light rain showers',81:'moderate rain showers',82:'violent rain showers',85:'light snow showers',86:'heavy snow showers',95:'thunderstorm',96:'thunderstorm with hail',99:'thunderstorm heavy hail'};
const RANK={none:0,HEADS_UP:1,URGENT:2};
const nowMs=Date.now(),nowDate=new Date(nowMs),state=$getWorkflowStaticData('global');

let cfg;
try { cfg=$('City config').first().json; }
catch(e) { cfg=$('Build form city config').first().json; }

const CITIES=cfg.CITIES||[],forceSeverity=cfg.forceSeverity||null,triggeredBy=cfg.route||'SCHEDULED';
const toAlert=[],failed=[],allItems=$input.all();

if(!allItems.length||allItems[0].json.error){
  return [{json:{toAlert:[],failed:CITIES.map(c=>({name:c.name,error:'fetch failed'})),hasAlerts:false,hasErrors:true,totalOutage:true,triggeredBy}}];}

for(let i=0;i<CITIES.length;i++){
  const city=CITIES[i],item=allItems[i];
  const t={rain_mm:parseFloat(city.thresholds.rain_mm),wind_kph:parseFloat(city.thresholds.wind_kph),snow_cm:parseFloat(city.thresholds.snow_cm),heat_c:parseFloat(city.thresholds.heat_c)};
  if(!item||!item.json.hourly){failed.push({name:city.name,error:'no data'});continue;}
  const h=item.json.hourly;
  function dir(deg){return['N','NE','E','SE','S','SW','W','NW'][Math.round((deg??0)/45)%8];}
  const hours=h.time.map((ts,j)=>({ts,hoursFromNow:(new Date(ts+'Z')-nowDate)/3600000,temp:h.temperature_2m[j]??0,rain:h.precipitation[j]??0,wind:h.windspeed_10m[j]??0,dir:dir(h.winddirection_10m[j]),code:h.weathercode[j]??0,snow:h.snowfall[j]??0,label:WMO[h.weathercode[j]]||'unknown'})).filter(h=>h.hoursFromNow>=-0.5&&h.hoursFromNow<=48);
  function score(h){let s=0;if(h.rain>t.rain_mm)s+=2;if(h.wind>t.wind_kph)s+=2;if(h.temp>t.heat_c)s+=1;if(h.snow>t.snow_cm&&t.snow_cm>0)s+=3;if(h.code>=95)s+=3;if(h.code>=71&&h.code<=77)s+=2;if(h.rain>t.rain_mm*0.7&&h.wind>t.wind_kph*0.7)s+=2;return s;}
  function bestIn(from,to){const w=hours.filter(h=>h.hoursFromNow>=from&&h.hoursFromNow<=to);if(!w.length)return{maxScore:0,peak:null};let best=0,peak=null;for(const h of w){const s=score(h);if(s>best){best=s;peak=h;}}return{maxScore:best,peak};}
  const windows={next6h:bestIn(0,6),tonight:bestIn(6,18),tomorrow:bestIn(18,36),extended:bestIn(36,48)};
  const top=Math.max(...Object.values(windows).map(w=>w.maxScore));
  let severity=forceSeverity||(windows.next6h.maxScore>=5||windows.tonight.maxScore>=5?'URGENT':top>=2?'HEADS_UP':'none');
  const key='city_'+city.name,last=state[key]||{severity:'none',ts:0},hrs=(nowMs-last.ts)/3600000;
  if(triggeredBy==='SCHEDULED'){
    if(severity==='none'){if(last.severity!=='none'&&hrs>=12)state[key]={severity:'none',ts:nowMs};continue;}
    if(!(RANK[severity]>RANK[last.severity]||hrs>=18))continue;
    state[key]={severity,ts:nowMs};
  }
  const fmt=new Intl.DateTimeFormat('en-GB',{timeZone:city.tz,hour:'2-digit',minute:'2-digit',weekday:'short',hour12:false});
  const parts=fmt.formatToParts(new Date()),hp=parts.find(p=>p.type==='hour'),wp=parts.find(p=>p.type==='weekday'),hour=hp?parseInt(hp.value,10):new Date().getUTCHours();
  toAlert.push({city:city.name,severity,windows,triggeredBy,localCtx:{time:fmt.format(new Date()),weekday:wp?wp.value:'unknown',isPeak:(hour>=11&&hour<=14)||(hour>=17&&hour<=22)}});
}
return [{json:{toAlert,failed,triggeredBy,hasAlerts:toAlert.length>0,hasErrors:failed.length>0,totalOutage:failed.length===CITIES.length}}];

const f=($input.first()||{json:{}}).json;
const name=f['City'],sev=f['Force severity'];
const D={
  Helsinki:{lat:60.17,lon:24.94,tz:'Europe/Helsinki',thresholds:{rain_mm:10,wind_kph:60,snow_cm:15,heat_c:30}},
  Tallinn: {lat:59.44,lon:24.75,tz:'Europe/Tallinn', thresholds:{rain_mm:10,wind_kph:55,snow_cm:20,heat_c:28}},
  Lisbon:  {lat:38.72,lon:-9.14,tz:'Europe/Lisbon',  thresholds:{rain_mm:15,wind_kph:50,snow_cm:1, heat_c:42}},
  Nairobi: {lat:-1.29,lon:36.82,tz:'Africa/Nairobi', thresholds:{rain_mm:40,wind_kph:45,snow_cm:999,heat_c:38}}
};
const city=D[name];if(!city)throw new Error('Unknown city: '+name);
const CITIES=[{name,...city}];
const url=`https://api.open-meteo.com/v1/forecast?latitude=${city.lat}&longitude=${city.lon}&hourly=temperature_2m,precipitation,windspeed_10m,winddirection_10m,weathercode,snowfall&forecast_days=2&timezone=UTC`;
return [{json:{route:'FORM',CITIES,url,forceSeverity:sev==='Auto-detect'?null:sev}}];

